enum Message {
    Quit,
    Move { x: i32, y: i32 },
    Write(String),
}

fn process_message(msg: Message) {
    match msg {
        Message::Quit => println!("Quitting"),
        Message::Move { x, y } => println!("Moving to {}, {}", x, y),
        Message::Write(s) => println!("Writing: {}", s),
    }
}

fn main() {
    process_message(Message::Write(String::from("Hello")));
}
